import{_ as s,o as a,c as t,ae as i}from"./chunks/framework.CNbcAk17.js";const u=JSON.parse('{"title":"Passkeys","description":"Use passkeys to secure dashboard editing and settings access.","frontmatter":{"description":"Use passkeys to secure dashboard editing and settings access."},"headers":[],"relativePath":"settings/passkeys.md","filePath":"settings/passkeys.md"}'),r={name:"settings/passkeys.md"};function o(n,e,l,d,c,p){return a(),t("div",null,[...e[0]||(e[0]=[i('<h1 id="passkeys" tabindex="-1">Passkeys <a class="header-anchor" href="#passkeys" aria-label="Permalink to &quot;Passkeys&quot;">​</a></h1><p>Magma supports passkey authentication using WebAuthn (Web Authentication API). Passkeys use biometrics — Face ID, Touch ID, Windows Hello, or a platform PIN — to verify your identity before allowing edit mode and settings access.</p><h2 id="how-it-works" tabindex="-1">How it works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How it works&quot;">​</a></h2><p>When at least one passkey is registered, the dashboard and settings pages prompt for passkey verification before granting access. This protects your configuration from unauthorized changes while keeping access convenient.</p><h2 id="register-a-passkey" tabindex="-1">Register a passkey <a class="header-anchor" href="#register-a-passkey" aria-label="Permalink to &quot;Register a passkey&quot;">​</a></h2><ol><li>Open <strong>Settings → Security</strong>.</li><li>Click <strong>Add Passkey</strong>.</li><li>Complete the browser prompt (Face ID, Touch ID, Windows Hello, or PIN).</li><li>The passkey appears in the list with a label and creation date.</li></ol><h2 id="use-a-passkey" tabindex="-1">Use a passkey <a class="header-anchor" href="#use-a-passkey" aria-label="Permalink to &quot;Use a passkey&quot;">​</a></h2><ul><li><strong>Dashboard edit mode:</strong> Press the edit button — the passkey prompt appears before the editor opens.</li><li><strong>Settings page:</strong> Visiting settings triggers the passkey prompt automatically.</li></ul><h2 id="manage-passkeys" tabindex="-1">Manage passkeys <a class="header-anchor" href="#manage-passkeys" aria-label="Permalink to &quot;Manage passkeys&quot;">​</a></h2><p>Passkeys are listed under <strong>Settings → Security</strong>. You can:</p><ul><li>View registered passkeys with their labels and creation dates.</li><li>Delete passkeys with the trash button.</li><li>Register additional passkeys (e.g., one per device).</li></ul><h2 id="storage" tabindex="-1">Storage <a class="header-anchor" href="#storage" aria-label="Permalink to &quot;Storage&quot;">​</a></h2><p>Passkey credentials are stored in <code>config/passkey.yaml</code> using the <code>@simplewebauthn/server</code> library. Credential public keys and counters are persisted so the server can verify authentication challenges.</p><h2 id="notes" tabindex="-1">Notes <a class="header-anchor" href="#notes" aria-label="Permalink to &quot;Notes&quot;">​</a></h2><ul><li>Passkeys are device-specific. Register a passkey on each device you want to use.</li><li>Deleting all passkeys removes the authentication gate — the dashboard returns to unrestricted access.</li><li>Passkey verification is handled entirely by the browser&#39;s platform authenticator; no external service or cloud provider is required.</li></ul>',15)])])}const g=s(r,[["render",o]]);export{u as __pageData,g as default};
